import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

/* ─── DESIGN TOKENS ──────────────────────────────────────────────────────── */
const POS = {
  bg:         "#0d1117",
  surface:    "#161b22",
  card:       "#1c2333",
  border:     "#30363d",
  accent:     "#f59e0b",
  accentDim:  "rgba(245,158,11,0.15)",
  green:      "#22c55e",
  greenDim:   "rgba(34,197,94,0.12)",
  blue:       "#3b82f6",
  blueDim:    "rgba(59,130,246,0.12)",
  red:        "#ef4444",
  muted:      "#8b949e",
  text:       "#e6edf3",
  textSub:    "#c9d1d9",
  sidebar:    "#0d1117",
  sideW:      220,
  orderW:     360,
};

const catEmoji = {
  food: "🍛", drink: "🥤", dessert: "🍰", snack: "🍿",
  beverage: "🥤", burger: "🍔", pizza: "🍕", pasta: "🍝",
  salad: "🥗", soup: "🍲", seafood: "🦐", chicken: "🍗",
  beef: "🥩", veg: "🥦", default: "🍽️",
};
const getCatIcon = (cat = "") => catEmoji[cat.toLowerCase()] || catEmoji.default;

const roundColors = ["#6366f1","#10b981","#f59e0b","#ec4899","#06b6d4","#8b5cf6"];
const getRoundLabel = (idx) => ["Round 1","Round 2","Round 3","Round 4","Round 5","Round 6"][idx] || `Round ${idx+1}`;
const getRoundOrdinal = (idx) => ["1st","2nd","3rd","4th","5th","6th"][idx] || `${idx+1}th`;

/* ─── MAIN COMPONENT ─────────────────────────────────────────────────────── */
export default function WaiterPanel() {
  const [tables,       setTables]       = useState([]);
  const [menu,         setMenu]         = useState([]);
  const [specials,     setSpecials]     = useState({});
  const [selectedTable,setSelectedTable]= useState(null);
  const [allRounds,    setAllRounds]    = useState([]);
  const [draftRoundIdx,setDraftRoundIdx]= useState(null);
  const [loading,      setLoading]      = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [view,         setView]         = useState("tables");
  const [confirmModal, setConfirmModal] = useState(false);
  const [confirming,   setConfirming]   = useState(false);
  const [activeOrderType, setActiveOrderType] = useState("table");
  const [taxSettings,  setTaxSettings]  = useState(null);
  const [activeCat,    setActiveCat]    = useState(null);
  const [activeSub,    setActiveSub]    = useState(null);
  const [searchQ,      setSearchQ]      = useState("");
  const { user, logout, theme, toggleTheme } = useAuth();
  const navigate  = useNavigate();
  const summaryRef = useRef(null);

  const loadData = useCallback(async () => {
    try {
      const [t, m, s, tax] = await Promise.all([
        API.get("/tables"), API.get("/menu"),
        API.get("/extras/specials"), API.get("/extras/tax-settings"),
      ]);
      setTables(t.data);
      const avail = m.data.filter(i => i.is_available);
      setMenu(avail);
      // auto-set first category
      const cats = [...new Set(avail.map(x => x.category))];
      if (cats.length) setActiveCat(prev => prev || cats[0]);
      const sMap = {};
      s.data.forEach(sp => {
        sMap[sp.menu_id] = { ...sp, discounted_price: sp.discount_pct > 0 ? Math.round(sp.price * (1 - sp.discount_pct/100)) : sp.price };
      });
      setSpecials(sMap);
      setTaxSettings(tax.data);
    } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const loadTableRounds = useCallback(async (table) => {
    setRoundLoading(true);
    try {
      const allOrdersRes = await API.get(`/orders/table/${table.id}/all`);
      const orders = allOrdersRes.data || [];
      if (orders.length === 0) { setAllRounds([]); setDraftRoundIdx(null); setRoundLoading(false); return; }
      const roundsWithItems = await Promise.all(orders.map(async (order, idx) => {
        try {
          const detail = await API.get(`/orders/${order.id}`);
          return { order: detail.data.order, items: detail.data.items || [], roundNumber: idx+1 };
        } catch { return { order, items: [], roundNumber: idx+1 }; }
      }));
      setAllRounds(roundsWithItems);
      const draftIdx = roundsWithItems.findIndex(r => r.order.status === "draft");
      setDraftRoundIdx(draftIdx === -1 ? null : draftIdx);
    } catch {}
    setRoundLoading(false);
  }, []);

  const refreshRound = async (roundIdx) => {
    const round = allRounds[roundIdx];
    if (!round) return;
    try {
      const detail = await API.get(`/orders/${round.order.id}`);
      setAllRounds(prev => { const u = [...prev]; u[roundIdx] = { ...u[roundIdx], order: detail.data.order, items: detail.data.items || [] }; return u; });
    } catch {}
  };

  const selectTable  = async (table) => { setSelectedTable(table); setActiveOrderType("table"); setView("order"); await loadTableRounds(table); };
  const startOrder   = async () => {
    if (!selectedTable) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table" });
      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0); await loadData();
    } catch (err) {
      if (err.response?.data?.order_id) await loadTableRounds(selectedTable);
    }
    setRoundLoading(false);
  };
  const startNewRound = async () => {
    if (!selectedTable || allRounds.some(r => r.order.status === "draft")) return;
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { table_id: selectedTable.id, order_type: "table", addendum: true });
      const newRound = { order: res.data, items: [], roundNumber: allRounds.length+1 };
      setAllRounds(prev => [...prev, newRound]);
      setDraftRoundIdx(allRounds.length);
      setTimeout(() => summaryRef.current?.scrollTo({ top: summaryRef.current.scrollHeight, behavior: "smooth" }), 200);
    } catch {}
    setRoundLoading(false);
  };
  const startTakeaway = async () => {
    setRoundLoading(true);
    try {
      const res = await API.post("/orders", { order_type: "takeaway" });
      setAllRounds([{ order: res.data, items: [], roundNumber: 1 }]);
      setDraftRoundIdx(0); setSelectedTable(null); setActiveOrderType("takeaway");
    } catch {}
    setRoundLoading(false);
    setView("order");
  };
  const addItem = async (menuItem) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    const special = specials[menuItem.id];
    const unit_price = special ? special.discounted_price : menuItem.price;
    try {
      await API.post(`/orders/${draftRound.order.id}/items`, { menu_id: menuItem.id, quantity: 1, unit_price });
      await refreshRound(draftRoundIdx);
    } catch {}
  };
  const removeItem = async (itemId) => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.order.status !== "draft") return;
    try { await API.delete(`/orders/${draftRound.order.id}/items/${itemId}`); await refreshRound(draftRoundIdx); } catch {}
  };
  const handleSendToKitchen = async () => {
    if (draftRoundIdx === null) return;
    const draftRound = allRounds[draftRoundIdx];
    if (!draftRound || draftRound.items.length === 0) return;
    setConfirming(true);
    try {
      await API.put(`/orders/${draftRound.order.id}/confirm`);
      await refreshRound(draftRoundIdx);
      setDraftRoundIdx(null); setConfirmModal(false); await loadData();
    } catch {}
    setConfirming(false);
  };
  const handleLogout = async () => { try { await API.post("/auth/logout"); } catch {} logout(); navigate("/"); };
  const goBack = () => { setView("tables"); setAllRounds([]); setDraftRoundIdx(null); setSelectedTable(null); loadData(); };

  // ── Derived ──
  const categories = [...new Set(menu.map(m => m.category))];
  const catItems    = menu.filter(m => m.category === activeCat);
  const subcats     = [...new Set(catItems.map(m => m.subcategory || "Others"))];

  const filteredItems = searchQ.trim()
    ? menu.filter(m => m.name.toLowerCase().includes(searchQ.toLowerCase()))
    : activeSub
      ? catItems.filter(m => (m.subcategory || "Others") === activeSub)
      : catItems;

  const combinedTotal     = allRounds.reduce((s, r) => s + Number(r.order?.total || 0), 0);
  const taxRate           = taxSettings ? parseFloat(taxSettings.tax_rate) || 13 : 13;
  const taxEnabled        = taxSettings ? taxSettings.tax_enabled !== false : false;
  const taxAmount         = taxEnabled ? parseFloat((combinedTotal * taxRate / 100).toFixed(2)) : 0;
  const grandTotal        = parseFloat((combinedTotal + taxAmount).toFixed(2));
  const hasSentRounds     = allRounds.some(r => r.order.status !== "draft");
  const draftRound        = draftRoundIdx !== null ? allRounds[draftRoundIdx] : null;
  const canAddItems       = draftRound !== null && draftRound.order.status === "draft";
  const draftItemCount    = draftRound?.items?.reduce((s, i) => s + i.quantity, 0) || 0;

  /* ── TABLE STATUS COLORS ── */
  const tableColor = (status) => ({
    available: { bg: "rgba(34,197,94,0.1)",    border: "#22c55e", text: "#22c55e"  },
    occupied:  { bg: "rgba(239,68,68,0.1)",    border: "#ef4444", text: "#ef4444"  },
    reserved:  { bg: "rgba(245,158,11,0.1)",   border: "#f59e0b", text: "#f59e0b"  },
  }[status] || { bg: POS.card, border: POS.border, text: POS.muted });

  /* ──────────────────────────────────────────────────────────────────────── */
  /*  RENDER                                                                   */
  /* ──────────────────────────────────────────────────────────────────────── */
  return (
    <div style={{ minHeight: "100vh", background: POS.bg, display: "flex", flexDirection: "column", fontFamily: "'DM Sans', system-ui, sans-serif", color: POS.text }}>
      <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700;800&family=Syne:wght@700;800&display=swap" rel="stylesheet" />

      {/* ── TOP HEADER BAR ─────────────────────────────────────────────── */}
      <header style={{
        background: POS.surface, borderBottom: `1px solid ${POS.border}`,
        padding: "0 20px", height: 58, display: "flex", alignItems: "center",
        justifyContent: "space-between", flexShrink: 0, gap: 12,
        boxShadow: "0 1px 20px rgba(0,0,0,0.4)",
      }}>
        {/* LEFT: Logo + nav */}
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <div style={{
            width: 36, height: 36, background: `linear-gradient(135deg,${POS.accent},#d97706)`,
            borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 18, flexShrink: 0, boxShadow: `0 0 14px ${POS.accent}40`,
          }}>🧑‍🍽️</div>
          <div>
            <div style={{ fontFamily: "'Syne',sans-serif", fontWeight: 800, fontSize: 14, letterSpacing: 0.5, color: POS.text }}>{user?.restaurant_name || "RestoPOS"}</div>
            <div style={{ fontSize: 11, color: POS.muted }}>{user?.name} · Waiter</div>
          </div>
          {view === "order" && (
            <button onClick={goBack} style={{
              marginLeft: 10, background: "none", border: `1px solid ${POS.border}`,
              borderRadius: 8, padding: "5px 14px", color: POS.muted, fontSize: 12,
              cursor: "pointer", transition: "all 0.2s",
            }}
              onMouseOver={e => e.currentTarget.style.color = POS.text}
              onMouseOut={e  => e.currentTarget.style.color = POS.muted}
            >← Tables</button>
          )}
        </div>

        {/* CENTER: Order type badge */}
        {view === "order" && (
          <div style={{
            background: activeOrderType === "takeaway"
              ? "linear-gradient(135deg,#f59e0b,#d97706)"
              : `linear-gradient(135deg,${POS.blue},#2563eb)`,
            color: "#fff", borderRadius: 10, padding: "6px 18px",
            fontWeight: 800, fontSize: 13, letterSpacing: 1, textTransform: "uppercase",
          }}>
            {activeOrderType === "takeaway" ? "📦 Takeaway" : `🪑 Table ${selectedTable?.table_number}`}
          </div>
        )}

        {/* RIGHT: Actions */}
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          {view === "tables" && (
            <button onClick={startTakeaway} style={{
              background: "linear-gradient(135deg,#f59e0b,#d97706)",
              border: "none", borderRadius: 10, padding: "8px 16px",
              color: "#fff", fontWeight: 800, fontSize: 13, cursor: "pointer",
              display: "flex", alignItems: "center", gap: 6,
              boxShadow: "0 2px 12px rgba(245,158,11,0.4)",
            }}>📦 Takeaway</button>
          )}
          <button onClick={toggleTheme} style={{
            background: POS.card, border: `1px solid ${POS.border}`,
            borderRadius: 8, padding: "7px 10px", color: POS.muted, fontSize: 14, cursor: "pointer",
          }}>{theme === "dark" ? "🌙" : "☀️"}</button>
          <button onClick={handleLogout} style={{
            background: "none", border: `1px solid ${POS.border}`,
            borderRadius: 8, padding: "7px 10px", color: POS.muted, fontSize: 13, cursor: "pointer",
          }}>🚪</button>
        </div>
      </header>

      {/* ── BODY ──────────────────────────────────────────────────────────── */}
      <div style={{ flex: 1, overflow: "hidden", display: "flex" }}>

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* TABLES VIEW                                                       */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {view === "tables" && (
          <div style={{ flex: 1, overflow: "auto", padding: 28 }}>
            {/* Specials banner */}
            {Object.keys(specials).length > 0 && (
              <div style={{
                background: "linear-gradient(135deg,rgba(245,158,11,0.08),rgba(245,158,11,0.04))",
                border: `1px solid ${POS.accent}40`, borderRadius: 14, padding: "12px 18px",
                marginBottom: 24, display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap",
              }}>
                <span style={{ fontSize: 16 }}>⭐</span>
                <span style={{ fontWeight: 700, color: POS.accent, fontSize: 13 }}>Today's Specials:</span>
                {Object.values(specials).map((sp, i) => (
                  <span key={i} style={{
                    background: POS.accent, color: "#000", borderRadius: 20,
                    padding: "3px 12px", fontSize: 12, fontWeight: 800,
                  }}>
                    {sp.name} — Rs.{sp.discounted_price}
                    {sp.discount_pct > 0 && ` (${sp.discount_pct}% off)`}
                  </span>
                ))}
              </div>
            )}

            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
              <div style={{ fontFamily: "'Syne',sans-serif", fontWeight: 800, fontSize: 22, color: POS.text }}>
                Select Table
              </div>
              <button onClick={loadData} style={{
                background: POS.card, border: `1px solid ${POS.border}`,
                borderRadius: 8, padding: "7px 14px", color: POS.muted, fontSize: 12, cursor: "pointer",
              }}>↻ Refresh</button>
            </div>

            {loading ? (
              <div style={{ display: "flex", justifyContent: "center", padding: 80 }}><div className="spinner" /></div>
            ) : (
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(150px,1fr))", gap: 14 }}>
                {tables.map(t => {
                  const c = tableColor(t.status);
                  return (
                    <div key={t.id} onClick={() => selectTable(t)} style={{
                      background: c.bg, border: `1.5px solid ${c.border}`,
                      borderRadius: 16, padding: "18px 14px", cursor: "pointer",
                      textAlign: "center", transition: "all 0.2s",
                      boxShadow: `0 0 0 0 ${c.border}`,
                    }}
                      onMouseOver={e => { e.currentTarget.style.transform = "translateY(-3px)"; e.currentTarget.style.boxShadow = `0 6px 20px ${c.border}40`; }}
                      onMouseOut={e  => { e.currentTarget.style.transform = "translateY(0)";   e.currentTarget.style.boxShadow = `0 0 0 0 ${c.border}`; }}
                    >
                      <div style={{ fontSize: 28, fontFamily: "'Syne',sans-serif", fontWeight: 800, color: c.text }}>
                        {t.table_number}
                      </div>
                      <div style={{ fontSize: 10, fontWeight: 700, color: c.text, textTransform: "uppercase", letterSpacing: 1, marginTop: 4 }}>{t.status}</div>
                      {t.status === "reserved" && t.reserved_by_name && (
                        <div style={{ fontSize: 10, color: POS.muted, marginTop: 4 }}>📋 {t.reserved_by_name}</div>
                      )}
                      <div style={{ fontSize: 11, color: POS.muted, marginTop: 6 }}>👥 {t.capacity} seats</div>
                    </div>
                  );
                })}
                {tables.length === 0 && (
                  <div style={{ gridColumn: "1/-1", textAlign: "center", padding: 60, color: POS.muted }}>
                    <div style={{ fontSize: 40, marginBottom: 12 }}>🪑</div>
                    <div style={{ fontWeight: 600 }}>No tables configured</div>
                  </div>
                )}
              </div>
            )}
          </div>
        )}

        {/* ═══════════════════════════════════════════════════════════════ */}
        {/* ORDER VIEW                                                        */}
        {/* ═══════════════════════════════════════════════════════════════ */}
        {view === "order" && (
          <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>

            {/* ── LEFT: CATEGORY SIDEBAR ──────────────────────────────── */}
            <div style={{
              width: POS.sideW, background: POS.sidebar,
              borderRight: `1px solid ${POS.border}`,
              display: "flex", flexDirection: "column", flexShrink: 0,
              overflowY: "auto",
            }}>
              <div style={{ padding: "14px 12px 8px", fontSize: 10, fontWeight: 700, color: POS.muted, textTransform: "uppercase", letterSpacing: 1.5 }}>Categories</div>

              {categories.map(cat => {
                const isActive = activeCat === cat && !searchQ;
                return (
                  <button key={cat} onClick={() => { setActiveCat(cat); setActiveSub(null); setSearchQ(""); }} style={{
                    display: "flex", alignItems: "center", gap: 10,
                    padding: "11px 12px", margin: "2px 8px", borderRadius: 10,
                    border: "none", cursor: "pointer", textAlign: "left", width: "calc(100% - 16px)",
                    background: isActive ? POS.accentDim : "none",
                    color: isActive ? POS.accent : POS.muted,
                    fontWeight: isActive ? 700 : 500,
                    transition: "all 0.15s",
                  }}
                    onMouseOver={e => { if (!isActive) { e.currentTarget.style.background = "rgba(255,255,255,0.04)"; e.currentTarget.style.color = POS.text; } }}
                    onMouseOut={e  => { if (!isActive) { e.currentTarget.style.background = "none"; e.currentTarget.style.color = POS.muted; } }}
                  >
                    <span style={{ fontSize: 17 }}>{getCatIcon(cat)}</span>
                    <span style={{ fontSize: 13, textTransform: "capitalize" }}>{cat}</span>
                    {isActive && <span style={{ marginLeft: "auto", width: 4, height: 4, borderRadius: "50%", background: POS.accent }} />}
                  </button>
                );
              })}

              {/* Subcategories */}
              {activeCat && subcats.length > 0 && !searchQ && (
                <>
                  <div style={{ margin: "12px 12px 4px", height: 1, background: POS.border }} />
                  <div style={{ padding: "8px 12px 4px", fontSize: 10, fontWeight: 700, color: POS.muted, textTransform: "uppercase", letterSpacing: 1.5 }}>
                    {activeCat.toUpperCase()}
                  </div>
                  <button onClick={() => setActiveSub(null)} style={{
                    display: "flex", alignItems: "center", gap: 8,
                    padding: "9px 12px", margin: "2px 8px", borderRadius: 8,
                    border: "none", cursor: "pointer", textAlign: "left", width: "calc(100% - 16px)",
                    background: !activeSub ? "rgba(255,255,255,0.06)" : "none",
                    color: !activeSub ? POS.text : POS.muted, fontSize: 12, fontWeight: !activeSub ? 600 : 400,
                  }}>
                    All
                  </button>
                  {subcats.map(sub => {
                    const isSubActive = activeSub === sub;
                    return (
                      <button key={sub} onClick={() => setActiveSub(sub)} style={{
                        display: "flex", alignItems: "center", gap: 8,
                        padding: "9px 12px", margin: "2px 8px", borderRadius: 8,
                        border: "none", cursor: "pointer", textAlign: "left", width: "calc(100% - 16px)",
                        background: isSubActive ? POS.accentDim : "none",
                        color: isSubActive ? POS.accent : POS.muted,
                        fontSize: 12, fontWeight: isSubActive ? 700 : 400,
                        transition: "all 0.15s",
                      }}
                        onMouseOver={e => { if (!isSubActive) { e.currentTarget.style.background = "rgba(255,255,255,0.04)"; e.currentTarget.style.color = POS.text; } }}
                        onMouseOut={e  => { if (!isSubActive) { e.currentTarget.style.background = "none"; e.currentTarget.style.color = POS.muted; } }}
                      >
                        <span style={{ fontSize: 14 }}>↳</span>
                        <span>{sub}</span>
                      </button>
                    );
                  })}
                </>
              )}
            </div>

            {/* ── CENTER: MENU GRID ─────────────────────────────────────── */}
            <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden" }}>
              {/* Search bar + round status */}
              <div style={{
                padding: "12px 18px", background: POS.surface,
                borderBottom: `1px solid ${POS.border}`,
                display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap",
              }}>
                <div style={{ flex: 1, minWidth: 180, position: "relative" }}>
                  <span style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)", color: POS.muted, fontSize: 14 }}>🔍</span>
                  <input
                    value={searchQ}
                    onChange={e => setSearchQ(e.target.value)}
                    placeholder="Search menu…"
                    style={{
                      width: "100%", background: POS.card, border: `1px solid ${POS.border}`,
                      borderRadius: 10, padding: "9px 12px 9px 34px", color: POS.text,
                      fontSize: 13, outline: "none", boxSizing: "border-box",
                    }}
                  />
                </div>

                {/* Round badges */}
                {allRounds.map((r, idx) => (
                  r.order.status !== "draft" && (
                    <span key={idx} style={{
                      background: `${roundColors[idx % roundColors.length]}18`,
                      color: roundColors[idx % roundColors.length],
                      border: `1px solid ${roundColors[idx % roundColors.length]}40`,
                      borderRadius: 20, padding: "4px 12px", fontSize: 11, fontWeight: 700,
                    }}>✅ {getRoundLabel(idx)} sent</span>
                  )
                ))}
                {draftRoundIdx !== null && (
                  <span style={{
                    background: "rgba(245,158,11,0.12)", color: "#f59e0b",
                    border: "1px solid rgba(245,158,11,0.35)", borderRadius: 20,
                    padding: "4px 12px", fontSize: 11, fontWeight: 700,
                  }}>✏️ {getRoundOrdinal(draftRoundIdx)} order</span>
                )}
              </div>

              {/* Menu items */}
              <div style={{ flex: 1, overflow: "auto", padding: 18 }}>
                {roundLoading ? (
                  <div style={{ display: "flex", justifyContent: "center", padding: 60 }}><div className="spinner" /></div>
                ) : allRounds.length === 0 && !roundLoading ? (
                  <div style={{ textAlign: "center", paddingTop: 60 }}>
                    <div style={{ fontSize: 50, marginBottom: 14 }}>🍽️</div>
                    <div style={{ fontWeight: 700, fontSize: 18, color: POS.text, marginBottom: 8 }}>
                      {activeOrderType === "takeaway" ? "New Takeaway" : `Table ${selectedTable?.table_number} is free`}
                    </div>
                    {activeOrderType === "table" && (
                      <button onClick={startOrder} style={{
                        background: `linear-gradient(135deg,${POS.accent},#d97706)`,
                        border: "none", borderRadius: 12, padding: "12px 28px",
                        color: "#000", fontWeight: 800, fontSize: 15, cursor: "pointer",
                        boxShadow: `0 4px 20px ${POS.accent}50`,
                      }}>🍽️ Start Order</button>
                    )}
                  </div>
                ) : (
                  <>
                    {/* Add another round prompt */}
                    {hasSentRounds && draftRoundIdx === null && activeOrderType !== "takeaway" && (
                      <div style={{
                        marginBottom: 16, background: `${POS.blue}10`,
                        border: `1px solid ${POS.blue}40`, borderRadius: 14,
                        padding: "14px 18px", display: "flex", alignItems: "center",
                        justifyContent: "space-between", gap: 12,
                      }}>
                        <div>
                          <div style={{ fontWeight: 700, fontSize: 14, color: POS.text }}>Need more items?</div>
                          <div style={{ fontSize: 12, color: POS.muted, marginTop: 2 }}>Only new items will be sent to the kitchen.</div>
                        </div>
                        <button onClick={startNewRound} style={{
                          background: `linear-gradient(135deg,${POS.blue},#2563eb)`,
                          border: "none", borderRadius: 10, padding: "9px 18px",
                          color: "#fff", fontWeight: 800, fontSize: 13, cursor: "pointer",
                          whiteSpace: "nowrap",
                        }}>➕ Add {getRoundOrdinal(allRounds.length)} Order</button>
                      </div>
                    )}

                    {/* Section label */}
                    {!searchQ && (
                      <div style={{ marginBottom: 14, display: "flex", alignItems: "center", gap: 10 }}>
                        <span style={{ fontSize: 20 }}>{getCatIcon(activeCat)}</span>
                        <span style={{ fontFamily: "'Syne',sans-serif", fontWeight: 800, fontSize: 17, color: POS.text, textTransform: "capitalize" }}>{activeSub || activeCat}</span>
                        <span style={{ fontSize: 12, color: POS.muted }}>({filteredItems.length} items)</span>
                      </div>
                    )}
                    {searchQ && (
                      <div style={{ marginBottom: 14, fontSize: 13, color: POS.muted }}>
                        🔍 Results for <strong style={{ color: POS.text }}>"{searchQ}"</strong> — {filteredItems.length} found
                      </div>
                    )}

                    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(160px,1fr))", gap: 12 }}>
                      {filteredItems.map(item => {
                        const special = specials[item.id];
                        const displayPrice = special ? special.discounted_price : item.price;
                        const inDraft = draftRound?.items?.find(i => i.menu_id === item.id || i.name === item.name);
                        return (
                          <button key={item.id} onClick={() => addItem(item)} disabled={!canAddItems} style={{
                            background: special
                              ? "linear-gradient(135deg,rgba(245,158,11,0.12),rgba(245,158,11,0.06))"
                              : inDraft
                                ? `${POS.green}10`
                                : POS.card,
                            border: `1.5px solid ${special ? POS.accent + "60" : inDraft ? POS.green + "60" : POS.border}`,
                            borderRadius: 14, padding: "14px 12px",
                            cursor: canAddItems ? "pointer" : "not-allowed",
                            textAlign: "left", transition: "all 0.18s",
                            color: POS.text, opacity: canAddItems ? 1 : 0.4,
                            position: "relative", display: "block",
                          }}
                            onMouseOver={e => { if (canAddItems) { e.currentTarget.style.borderColor = POS.accent; e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = `0 6px 20px rgba(245,158,11,0.15)`; } }}
                            onMouseOut={e  => { e.currentTarget.style.borderColor = special ? POS.accent+"60" : inDraft ? POS.green+"60" : POS.border; e.currentTarget.style.transform = "translateY(0)"; e.currentTarget.style.boxShadow = "none"; }}
                          >
                            {special && (
                              <div style={{
                                position: "absolute", top: -9, right: 10,
                                background: POS.accent, color: "#000",
                                fontSize: 9, fontWeight: 900, borderRadius: 20, padding: "2px 8px",
                              }}>
                                {special.label || `${special.discount_pct}% OFF`}
                              </div>
                            )}
                            {inDraft && (
                              <div style={{
                                position: "absolute", top: -9, left: 10,
                                background: POS.green, color: "#fff",
                                fontSize: 9, fontWeight: 900, borderRadius: 20, padding: "2px 8px",
                              }}>✓ ADDED</div>
                            )}
                            <div style={{ fontSize: 11, color: POS.muted, marginBottom: 5, textTransform: "capitalize" }}>
                              {item.subcategory || item.category}
                            </div>
                            <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 8, lineHeight: 1.3, color: POS.text }}>
                              {item.name}
                            </div>
                            <div style={{ display: "flex", alignItems: "center", gap: 6, justifyContent: "space-between" }}>
                              <span style={{ color: POS.accent, fontWeight: 800, fontSize: 14 }}>
                                Rs.{Number(displayPrice).toLocaleString()}
                              </span>
                              {special && special.discount_pct > 0 && (
                                <span style={{ textDecoration: "line-through", fontSize: 11, color: POS.muted }}>
                                  Rs.{Number(item.price).toLocaleString()}
                                </span>
                              )}
                              <span style={{
                                width: 24, height: 24, borderRadius: "50%",
                                background: canAddItems ? POS.accentDim : "rgba(255,255,255,0.05)",
                                display: "flex", alignItems: "center", justifyContent: "center",
                                fontSize: 14, color: POS.accent, flexShrink: 0,
                              }}>+</span>
                            </div>
                          </button>
                        );
                      })}
                      {filteredItems.length === 0 && (
                        <div style={{ gridColumn: "1/-1", textAlign: "center", padding: 40, color: POS.muted }}>
                          <div style={{ fontSize: 32, marginBottom: 10 }}>🔍</div>
                          <div>No items found</div>
                        </div>
                      )}
                    </div>
                  </>
                )}
              </div>
            </div>

            {/* ── RIGHT: ORDER PANEL ────────────────────────────────────── */}
            <div style={{
              width: POS.orderW, background: POS.surface,
              borderLeft: `1px solid ${POS.border}`,
              display: "flex", flexDirection: "column", flexShrink: 0,
            }}>
              {/* Panel header */}
              <div style={{
                padding: "16px 18px 14px", borderBottom: `1px solid ${POS.border}`,
                background: POS.card,
              }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div style={{ fontFamily: "'Syne',sans-serif", fontWeight: 800, fontSize: 15, color: POS.text }}>
                    Order Summary
                  </div>
                  {allRounds.length > 0 && (
                    <span style={{
                      background: POS.greenDim, color: POS.green,
                      border: `1px solid ${POS.green}40`, borderRadius: 20,
                      padding: "2px 10px", fontSize: 11, fontWeight: 700,
                    }}>
                      {allRounds.filter(r => r.order.status !== "draft").length}/{allRounds.length} sent
                    </span>
                  )}
                </div>
                <div style={{ fontSize: 11, color: POS.muted, marginTop: 3 }}>
                  {activeOrderType === "takeaway" ? "📦 Takeaway Order"
                    : selectedTable ? `Table ${selectedTable.table_number} · ${allRounds.length} round${allRounds.length !== 1 ? "s" : ""}`
                    : "No active order"}
                </div>
                {draftItemCount > 0 && (
                  <div style={{ marginTop: 8, fontSize: 12, color: POS.accent, fontWeight: 600 }}>
                    🛒 {draftItemCount} item{draftItemCount !== 1 ? "s" : ""} in current round
                  </div>
                )}
              </div>

              {/* Scrollable rounds */}
              <div ref={summaryRef} style={{ flex: 1, overflowY: "auto" }}>
                {allRounds.length === 0 && (
                  <div style={{ padding: "40px 18px", textAlign: "center", color: POS.muted, fontSize: 13 }}>
                    {activeOrderType === "table" ? "Start an order to add items" : "Add items to takeaway order"}
                  </div>
                )}

                {allRounds.map((round, idx) => {
                  const isSent  = round.order.status !== "draft";
                  const isDraft = round.order.status === "draft";
                  const color   = roundColors[idx % roundColors.length];
                  return (
                    <div key={round.order.id}>
                      {/* Round header */}
                      <div style={{
                        padding: "10px 16px",
                        background: isDraft ? `${color}10` : POS.bg,
                        borderBottom: `1px solid ${POS.border}`,
                        borderTop: idx > 0 ? `2px solid ${POS.border}` : "none",
                        display: "flex", justifyContent: "space-between", alignItems: "center",
                      }}>
                        <span style={{ fontSize: 11, fontWeight: 800, color: isDraft ? color : POS.muted, textTransform: "uppercase", letterSpacing: 0.8 }}>
                          {getRoundLabel(idx)}
                          {isDraft && <span style={{ fontWeight: 500, textTransform: "none", marginLeft: 6, fontSize: 11 }}>(draft)</span>}
                        </span>
                        <span style={{ fontSize: 11, color: isSent ? POS.green : color, fontWeight: 700 }}>
                          {isSent ? "✅ Sent" : "✏️ Draft"}
                        </span>
                      </div>

                      {/* Items */}
                      <div>
                        {round.items.length === 0 ? (
                          <div style={{ padding: "16px 16px", textAlign: "center", color: POS.muted, fontSize: 12 }}>
                            Tap menu items to add
                          </div>
                        ) : round.items.map(item => (
                          <div key={item.id} style={{
                            display: "flex", alignItems: "center", gap: 10,
                            padding: "10px 16px", borderBottom: `1px solid ${POS.border}30`,
                            background: isDraft ? `${color}05` : "transparent",
                          }}>
                            <div style={{ flex: 1 }}>
                              <div style={{ fontWeight: 600, fontSize: 13, color: POS.text }}>{item.name}</div>
                              <div style={{ fontSize: 11, color: POS.muted }}>×{item.quantity}</div>
                            </div>
                            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                              <span style={{ fontWeight: 700, color: isDraft ? color : POS.green, fontSize: 13 }}>
                                Rs.{Number(item.price).toLocaleString()}
                              </span>
                              {isDraft && (
                                <button onClick={() => removeItem(item.id)} style={{
                                  background: "rgba(239,68,68,0.12)", border: "none",
                                  borderRadius: 6, width: 22, height: 22, display: "flex",
                                  alignItems: "center", justifyContent: "center",
                                  color: POS.red, fontSize: 14, cursor: "pointer", fontWeight: 900,
                                }}>×</button>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>

                      {/* Round subtotal */}
                      <div style={{
                        padding: "8px 16px", display: "flex",
                        justifyContent: "space-between", fontSize: 12,
                        borderBottom: `1px solid ${POS.border}`,
                        background: POS.bg,
                      }}>
                        <span style={{ color: POS.muted }}>{getRoundLabel(idx)} subtotal</span>
                        <span style={{ fontWeight: 700, color: isSent ? POS.text : color }}>
                          Rs.{Number(round.order?.total || 0).toLocaleString()}
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* TOTAL BAR */}
              {allRounds.length > 0 && (
                <div style={{ padding: "14px 18px", borderTop: `1px solid ${POS.border}`, background: POS.card }}>
                  {taxEnabled && (
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: POS.muted, marginBottom: 4 }}>
                      <span>Subtotal</span>
                      <span>Rs.{combinedTotal.toLocaleString()}</span>
                    </div>
                  )}
                  {taxEnabled && (
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 12, color: POS.muted, marginBottom: 8 }}>
                      <span>VAT ({taxRate}%)</span>
                      <span>Rs.{taxAmount.toLocaleString()}</span>
                    </div>
                  )}
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <div>
                      <div style={{ fontWeight: 800, fontSize: 15, color: POS.text }}>Grand Total</div>
                      {taxEnabled && <div style={{ fontSize: 10, color: POS.muted }}>VAT inclusive</div>}
                    </div>
                    <span style={{ color: POS.green, fontSize: 22, fontWeight: 900, fontFamily: "'Syne',sans-serif" }}>
                      Rs.{grandTotal.toLocaleString()}
                    </span>
                  </div>
                </div>
              )}

              {/* SEND TO KITCHEN */}
              {draftRound && draftRound.items.length > 0 && (
                <div style={{ padding: "12px 16px", borderTop: `1px solid ${POS.border}` }}>
                  <button onClick={() => setConfirmModal(true)} style={{
                    width: "100%", padding: "13px 0",
                    background: `linear-gradient(135deg,${roundColors[draftRoundIdx % roundColors.length]},${roundColors[(draftRoundIdx+1) % roundColors.length]})`,
                    border: "none", borderRadius: 12, color: "#fff",
                    fontWeight: 900, fontSize: 15, cursor: "pointer",
                    boxShadow: `0 4px 18px ${roundColors[draftRoundIdx % roundColors.length]}50`,
                    transition: "transform 0.15s",
                  }}
                    onMouseOver={e => e.currentTarget.style.transform = "scale(1.02)"}
                    onMouseOut={e  => e.currentTarget.style.transform = "scale(1)"}
                  >
                    🚀 Send {getRoundLabel(draftRoundIdx)} to Kitchen
                  </button>
                  <div style={{ fontSize: 11, color: POS.muted, textAlign: "center", marginTop: 6 }}>
                    Only new items — no duplication
                  </div>
                </div>
              )}

              {/* All sent state */}
              {allRounds.length > 0 && draftRoundIdx === null && (
                <div style={{ padding: "12px 16px", borderTop: `1px solid ${POS.border}` }}>
                  <div style={{
                    background: POS.greenDim, border: `1px solid ${POS.green}40`,
                    borderRadius: 10, padding: "10px 14px", textAlign: "center",
                    color: POS.green, fontWeight: 700, fontSize: 13, marginBottom: 8,
                  }}>✅ All rounds sent to kitchen</div>
                  {activeOrderType !== "takeaway" && (
                    <button onClick={startNewRound} style={{
                      width: "100%", padding: "10px 0",
                      background: POS.card, border: `1px solid ${POS.border}`,
                      borderRadius: 10, color: POS.text, fontWeight: 700,
                      fontSize: 13, cursor: "pointer",
                    }}>➕ Add {getRoundOrdinal(allRounds.length)} Order</button>
                  )}
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* ── CONFIRM MODAL ─────────────────────────────────────────────────── */}
      {confirmModal && draftRound && (
        <div style={{
          position: "fixed", inset: 0, background: "rgba(0,0,0,0.75)",
          display: "flex", alignItems: "center", justifyContent: "center",
          zIndex: 1000, backdropFilter: "blur(4px)",
        }} onClick={() => setConfirmModal(false)}>
          <div onClick={e => e.stopPropagation()} style={{
            background: POS.surface, border: `1px solid ${POS.border}`,
            borderRadius: 20, width: 420, maxWidth: "90vw",
            boxShadow: "0 20px 60px rgba(0,0,0,0.7)",
          }}>
            <div style={{ padding: "20px 22px", borderBottom: `1px solid ${POS.border}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ fontFamily: "'Syne',sans-serif", fontWeight: 800, fontSize: 17, color: POS.text }}>
                🚀 Send {getRoundLabel(draftRoundIdx)} to Kitchen
              </div>
              <button onClick={() => setConfirmModal(false)} style={{ background: "none", border: "none", color: POS.muted, fontSize: 20, cursor: "pointer" }}>✕</button>
            </div>

            <div style={{ padding: "20px 22px" }}>
              <div style={{ textAlign: "center", marginBottom: 18 }}>
                <div style={{ fontSize: 44, marginBottom: 10 }}>
                  {activeOrderType === "takeaway" ? "📦" : draftRoundIdx === 0 ? "🍽️" : "➕"}
                </div>
                <div style={{ fontWeight: 700, fontSize: 16, color: POS.text, marginBottom: 4 }}>
                  {activeOrderType === "takeaway" ? "Send to Kitchen?" : `Table ${selectedTable?.table_number} — ${getRoundLabel(draftRoundIdx)}`}
                </div>
                {draftRoundIdx > 0 && (
                  <div style={{ color: POS.muted, fontSize: 13 }}>Only these new items go to the kitchen.</div>
                )}
              </div>

              <div style={{ background: POS.card, borderRadius: 12, padding: "14px 16px", border: `1px solid ${POS.border}` }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: POS.muted, textTransform: "uppercase", letterSpacing: 1, marginBottom: 12 }}>
                  Items — {getRoundLabel(draftRoundIdx)}
                </div>
                {draftRound.items.map((item, i) => (
                  <div key={i} style={{
                    display: "flex", justifyContent: "space-between",
                    fontSize: 13, padding: "6px 0",
                    borderBottom: i < draftRound.items.length - 1 ? `1px solid ${POS.border}40` : "none",
                  }}>
                    <span style={{ color: POS.text, fontWeight: 600 }}>{item.name}</span>
                    <span style={{ color: POS.muted }}>×{item.quantity}</span>
                  </div>
                ))}
              </div>
            </div>

            <div style={{ padding: "16px 22px", borderTop: `1px solid ${POS.border}`, display: "flex", gap: 10 }}>
              <button onClick={() => setConfirmModal(false)} style={{
                flex: 1, padding: "11px 0", background: POS.card,
                border: `1px solid ${POS.border}`, borderRadius: 10,
                color: POS.muted, fontWeight: 600, fontSize: 14, cursor: "pointer",
              }}>Cancel</button>
              <button onClick={handleSendToKitchen} disabled={confirming} style={{
                flex: 2, padding: "11px 0",
                background: `linear-gradient(135deg,${roundColors[draftRoundIdx % roundColors.length]},${roundColors[(draftRoundIdx+1) % roundColors.length]})`,
                border: "none", borderRadius: 10, color: "#fff",
                fontWeight: 900, fontSize: 14, cursor: "pointer",
                opacity: confirming ? 0.7 : 1,
              }}>
                {confirming ? "Sending…" : "✅ Confirm & Send"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
